mapper.select:
SELECT /* @SQLID=SUB020504-01#SQL001 */ * FROM ( SELECT count(*) over () as totalRow , A.BROKER_CODE , A.BROKER_NAME , A.BROKER_CHARGE_CODE , A.BROKER_CHARGE_NAME , A.BUTEN_CODE , A.ACCOUNT_NUMBER , A.DEALER_NUMBER , A.NAME_KANJI , A.SUM_DATE AS SUM_DATE , B.ADVISORY_FEE_COLLECTION_ID , C.NAME AS ADVISORY_SERVICE_ID , A.FEE FROM T_REWARD_COMMISSION A
INNER JOIN ( SELECT MSR.BROKER_CODE AS BROKER_CODE_MSR , MSR.DEALER_NUMBER , MC1.CODE_2 , MSR.START_DATE_YM AS START_DATE_MSR , MSR.END_DATE_YM AS END_DATE_MSR , MC1.START_DATE AS START_DATE_MC1 , MC1.END_DATE AS END_DATE_MC1 FROM M_SBIWRAP_REWARD MSR INNER JOIN M_CODE MC1 ON MC1.NAME = MSR.ADVISORY_SERVICE_ID AND MC1.CODE_1 = '30' AND MC1.CODE_TYPE = '50' AND MSR.FEE_RATE <> 0 AND MSR.REWARD_RATE <> 0 ) T ON A.BROKER_CODE = T.BROKER_CODE_MSR AND A.DEALER_NUMBER = T.DEALER_NUMBER AND A.KBN_CD = T.CODE_2 AND A.SUM_DATE >= T.START_DATE_MC1 AND A.SUM_DATE <= T.END_DATE_MC1 AND TO_CHAR(IFA_DATE_UTIL.IFA_GET_DATE, 'YYYYMM') >= T.START_DATE_MC1 AND TO_CHAR(IFA_DATE_UTIL.IFA_GET_DATE, 'YYYYMM') <= T.END_DATE_MC1 AND A.SUM_DATE >= T.START_DATE_MSR AND A.SUM_DATE <= T.END_DATE_MSR AND TO_CHAR(IFA_DATE_UTIL.IFA_GET_DATE, 'YYYYMM') >= T.START_DATE_MSR AND TO_CHAR(IFA_DATE_UTIL.IFA_GET_DATE, 'YYYYMM') <= T.END_DATE_MSR
LEFT OUTER JOIN T_TRC_SAFI_REF B ON A.RECORD_ID = B.RECORD_ID AND A.SUM_DATE = B.ADVISORY_FEE_COLLECTION_DATE LEFT OUTER JOIN M_CODE C ON TO_NUMBER(A.SUM_DATE) BETWEEN TO_NUMBER(C.START_DATE) AND TO_NUMBER(C.END_DATE) AND C.CODE_2 = A.KBN_CD AND C.CODE_1 = '30' AND C.CODE_TYPE = '50' WHERE A.PRODUT_CD = '30'
AND A.BUTEN_CODE = #{req.butenCode}
AND A.ACCOUNT_NUMBER = TO_NUMBER(#{req.accountNumber})
AND TO_CHAR(A.SUM_DATE) >= REPLACE(#{req.registeredDateFrom}, '/') AND TO_CHAR(A.SUM_DATE) <= REPLACE(#{req.registeredDateTo}, '/')
AND 1 = 1
AND (BROKER_CODE IN
) OR BROKER_CODE IN(
,
#{brokerChargeList.brokerCode}
)
AND ((BROKER_CODE, BROKER_CHARGE_CODE) IN
) OR (BROKER_CODE, BROKER_CHARGE_CODE) IN(
,
(#{brokerChargeList.brokerCode}, #{brokerChargeList.empCode})
)
AND A.BROKER_CODE IN
#{brokerCode}
AND A.BROKER_CODE NOT IN
#{brokerCode}
ORDER BY A.SUM_DATE DESC , A.BROKER_BRANCH_CODE ASC , A.BUTEN_CODE ASC , A.ACCOUNT_NUMBER ASC ) WHERE ROWNUM <= #{req.querySizeLimit}
